build:{
	master OpenHarmony_feature_20250702

	# init
	repo init -u https://gitcode.com/openharmony/manifest.git -b master --no-repo-verify

	# 对于重新拉代码回退掉所有本地修改
	repo forall -c 'git reset --hard'

	# sync
	repo sync -c
	repo sync -c -j$(nproc)
	repo sync -c -j$(nproc) --force-sync

	repo forall -c 'git lfs pull'

	cd third_party/libnl/ && git reset --hard 1d68314accd3a3e6806b0447b49e65f8ab018190 && cd ../..

	bash build/prebuilts_download.sh && ./build.sh --product-name rk3568 --ccache

	# 编译image
	./build.sh --product-name rk3568 --ccache

	# 快编so
	./build.sh --product-name rk3568 -T ace_engine --fast-rebuild
	./build.sh --product-name rk3568 -T app_bar_test_ng

	# 编译测试套
	./build.sh --product-name rk3568 -T 

	# 编译ace_engine 测试套
	./build.sh -p rk3568 -T ace_engine_test
	./build.sh -p rk3568 --build-target pipeline_context_test_ng app_bar_test_ng menu_test_ng

	# 编译sdk
	./build.sh --product-name ohos-sdk

	# 查找门禁 编译的TDD有那些测试套, 下载TDD产物, 搜索关键字 Excuting ninja
	./build.sh -p rk3568 -T foundation/arkui/ace_engine/test/unittest/capi/modifiers:capi_all_modifiers_test foundation/arkui/ace_engine/test/unittest/capi/utils:capi_all_utils_test_resource_copy foundation/arkui/ace_engine/test/unittest/capi/accessors:capi_all_accessors_test_resource_copy foundation/arkui/ace_engine/test/unittest/capi/accessors:capi_all_accessors_test foundation/arkui/ace_engine/test/unittest/capi/modifiers:capi_all_modifiers_test_resource_copy foundation/arkui/ace_engine/test/unittest/capi/modifiers/generated:capi_generated_modifiers_test_resource_copy foundation/arkui/ace_engine/test/unittest/capi/modifiers/generated:capi_generated_modifiers_test foundation/arkui/ace_engine/test/unittest/core/base:view_abstract_model_test_ng foundation/arkui/ace_engine/test/unittest/core/layout:layout_wrapper_test_ng foundation/arkui/ace_engine/test/unittest/core/manager:drag_drop_controller_func_wrapper_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/grid:grid_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/grid:grid_test_regular foundation/arkui/ace_engine/test/unittest/core/pattern/list:list_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/menu:menu_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/overlay:overlay_manager_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/select:select_test_ng foundation/arkui/ace_engine/test/unittest/core/pattern/text_input:text_input_pattern_test foundation/arkui/ace_engine/test/unittest/core/pattern/web:web_pattern_unit_test_ohos_part_one foundation/arkui/ace_engine/test/unittest/core/svg:svg_node_test_ng_resource_copy foundation/arkui/ace_engine/test/unittest/core/svg:svg_context_test_ng_resource_copy foundation/arkui/ace_engine/test/unittest/core/svg:svg_utils_test_ng_resource_copy foundation/arkui/ace_engine/test/unittest/core/svg:svg_dom_test_ng_resource_copy foundation/arkui/ace_engine/test/unittest/core/svg:parse_test_ng_resource_copy foundation/arkui/a